import{_ as e,o as s,c as t,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Garantias de entrega y orden","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/kafka/10-garantias-de-entrega-y-orden.md","filePath":"data-engineering/kafka/10-garantias-de-entrega-y-orden.md","lastUpdated":1782521464000}'),o={name:"data-engineering/kafka/10-garantias-de-entrega-y-orden.md"};function i(r,a,d,c,p,l){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="garantias-de-entrega-y-orden" tabindex="-1">Garantias de entrega y orden <a class="header-anchor" href="#garantias-de-entrega-y-orden" aria-label="Permalink to &quot;Garantias de entrega y orden&quot;">​</a></h1><p>Kafka ofrece piezas para construir sistemas fiables, pero las garantias finales dependen de configuracion, consumidores y sistemas externos.</p><h2 id="orden" tabindex="-1">Orden <a class="header-anchor" href="#orden" aria-label="Permalink to &quot;Orden&quot;">​</a></h2><p>Kafka garantiza orden dentro de una partition.</p><p>Si necesitas orden por pedido:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key = order_id</span></span></code></pre></div><p>Todos los eventos del mismo pedido iran a la misma partition.</p><h2 id="at-most-once" tabindex="-1">At most once <a class="header-anchor" href="#at-most-once" aria-label="Permalink to &quot;At most once&quot;">​</a></h2><p>Puede perder eventos si confirmas antes de procesar.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commit offset -&gt; procesar -&gt; fallo</span></span></code></pre></div><p>El evento queda marcado como leido aunque no se haya procesado.</p><h2 id="at-least-once" tabindex="-1">At least once <a class="header-anchor" href="#at-least-once" aria-label="Permalink to &quot;At least once&quot;">​</a></h2><p>Puede duplicar eventos, pero evita perdida si el consumidor es idempotente.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>procesar -&gt; fallo antes de commit -&gt; reprocesar</span></span></code></pre></div><p>Es el modelo practico mas habitual.</p><h2 id="exactly-once" tabindex="-1">Exactly once <a class="header-anchor" href="#exactly-once" aria-label="Permalink to &quot;Exactly once&quot;">​</a></h2><p>Kafka soporta transacciones e idempotent producers para escenarios Kafka-to-Kafka.</p><p>Limitacion importante: si escribes en una base externa, necesitas coordinar idempotencia o transacciones fuera de Kafka.</p><h2 id="productor-idempotente" tabindex="-1">Productor idempotente <a class="header-anchor" href="#productor-idempotente" aria-label="Permalink to &quot;Productor idempotente&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enable.idempotence=true</span></span>
<span class="line"><span>acks=all</span></span>
<span class="line"><span>retries&gt;0</span></span></code></pre></div><p>Ayuda a evitar duplicados por reintentos del producer.</p><h2 id="transacciones" tabindex="-1">Transacciones <a class="header-anchor" href="#transacciones" aria-label="Permalink to &quot;Transacciones&quot;">​</a></h2><p>Permiten producir en varios partitions/topics y confirmar offsets de consumo como una unidad dentro de Kafka.</p><p>Util para:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>consume topic A -&gt; transform -&gt; produce topic B</span></span></code></pre></div><h2 id="consumidor-idempotente" tabindex="-1">Consumidor idempotente <a class="header-anchor" href="#consumidor-idempotente" aria-label="Permalink to &quot;Consumidor idempotente&quot;">​</a></h2><p>Patron:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Leer event_id.</span></span>
<span class="line"><span>2. Comprobar si ya fue procesado.</span></span>
<span class="line"><span>3. Si no, ejecutar efecto.</span></span>
<span class="line"><span>4. Guardar event_id procesado.</span></span>
<span class="line"><span>5. Commit offset.</span></span></code></pre></div><h2 id="duplicados" tabindex="-1">Duplicados <a class="header-anchor" href="#duplicados" aria-label="Permalink to &quot;Duplicados&quot;">​</a></h2><p>Asume duplicados cuando:</p><ul><li>Hay reintentos.</li><li>El consumer cae despues de procesar y antes de commit.</li><li>Se reprocesan offsets.</li><li>Hay errores de red.</li></ul><h2 id="perdida-de-eventos" tabindex="-1">Perdida de eventos <a class="header-anchor" href="#perdida-de-eventos" aria-label="Permalink to &quot;Perdida de eventos&quot;">​</a></h2><p>Riesgos:</p><ul><li><code>acks=0</code>.</li><li><code>acks=1</code> y fallo del leader antes de replicar.</li><li><code>min.insync.replicas</code> mal configurado.</li><li>Retencion demasiado corta.</li><li>Consumidores que hacen commit antes de persistir.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa keys para ordenar por entidad.</li><li>No prometas orden global.</li><li>Diseña consumidores idempotentes.</li><li>Usa <code>acks=all</code> en eventos importantes.</li><li>Ajusta <code>min.insync.replicas</code>.</li><li>Documenta semantica real: at-least-once, exactly-once Kafka-to-Kafka, etc.</li></ul>`,36)])])}const m=e(o,[["render",i]]);export{h as __pageData,m as default};
